 1	import * as React from 'react';
 2	import {
 3	  ClipboardCopy,
 4	  ClipboardCopyVariant,
 5	  DescriptionList,
 6	  DescriptionListDescription,
 7	  DescriptionListGroup,
 8	  DescriptionListTerm,
 9	} from '@patternfly/react-core';
10	import { useTranslation } from 'react-i18next';
11	
12	import { RouteTemplate } from '../utils/triggers';
13	import './TriggerTemplateResourceLink.scss';
14	import { getReferenceForModel } from '../pipelines-overview/utils';
15	import { K8sKind, ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
16	
17	type TriggerTemplateResourceLinkProps = {
18	  namespace: string;
19	  model: K8sKind;
20	  links: RouteTemplate[];
21	};
22	const TriggerTemplateResourceLink: React.FC<
23	  TriggerTemplateResourceLinkProps
24	> = ({ links = [], namespace, model }) => {
25	  const { t } = useTranslation('plugin__pipelines-console-plugin');
26	  const title = t(model.labelPluralKey);
27	  const kind = getReferenceForModel(model);
28	
29	  if (links.length === 0) {
30	    return null;
31	  }
32	  return (
33	    <DescriptionList className="odc-trigger-template-list">
34	      <DescriptionListGroup>
35	        <DescriptionListTerm>{title}</DescriptionListTerm>
36	        {links.map(({ routeURL, triggerTemplateName }) => {
37	          return (
38	            <DescriptionListDescription key={triggerTemplateName}>
39	              <ResourceLink
40	                kind={kind}
41	                name={triggerTemplateName}
42	                namespace={namespace}
43	                title={triggerTemplateName}
44	                inline
45	              />
46	              {routeURL && (
47	                <div>
48	                  <ClipboardCopy variant={ClipboardCopyVariant.inlineCompact}>
49	                    {routeURL}
50	                  </ClipboardCopy>
51	                </div>
52	              )}
53	            </DescriptionListDescription>
54	          );
55	        })}
56	      </DescriptionListGroup>
57	    </DescriptionList>
58	  );
59	};
60	
61	export default TriggerTemplateResourceLink;

